var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"5년 후 현재","JPN":"5年後、現在","ENG":"5 years later, present day","TWN":"5年後的現在","DEU":"5 years later, present day","FRA":"5 years later, present day"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"프론트 베이 격벽 <color=#ffd34c>징역노동자 근무구역</color> ","JPN":"フロントベイの隔壁、<color=#ffd34c>懲役労働者の勤務エリア</color> ","ENG":"Front Bay Bulwark <color=#ffd34c>Sentenced Laborer Area</color>","TWN":"前灣隔離牆<color=#ffd34c>服勞役區域</color> ","DEU":"Front Bay Bulwark <color=#ffd34c>Sentenced Laborer Area</color>","FRA":"Front Bay Bulwark <color=#ffd34c>Sentenced Laborer Area</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"기준치 이상의 침식파가 감지되었습니다.","JPN":"基準値以上の侵食波が感知されました。","ENG":"An abnormally high Corruption ray has been detected.","TWN":"已偵測超出基準值的侵蝕波。"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"격벽 노동자분들은 모두 지정된 대피소로 이동해주시기 바랍니다.","JPN":"隔壁の労働者の皆さんは、指定された避難所まで移動してください。","ENG":"All bulwark workers, please proceed to the designated shelters.","TWN":"隔離牆作業人員請立即前往指定避難所。"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"다시 한번 알려드립니다.","JPN":"もう一度お知らせします。","ENG":"I repeat.","TWN":"再重複一次。"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"격벽 노동자분들은…….","JPN":"隔壁の労働者の皆さんは……","ENG":"All bulwark workers...","TWN":"隔離牆作業人員請……"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장, 검은 범람이 끝난 지 얼마나 됐다고 벌써 이런 일이 일어나는 거야?","JPN":"くそっ、つい最近黒い氾濫が終わったばかりだってのに、またか？","ENG":"Damn it, how long's it been since the Black Flood ended? Why's this happening already?","TWN":"可惡。黑色洪災才剛結束，怎麼又來了？"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_MONITOR","text":{"KOREA":"격벽 보수 공사는 중지해!","JPN":"隔壁の補修工事は中止だ！","ENG":"Stop all bulwark repairs!","TWN":"立刻停止隔離牆修復工程！"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_MONITOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_MONITOR","text":{"KOREA":"침식체들이 기어 올라오기 전에 서둘러 대피해라!","JPN":"侵食体どもが這いあがってくる前に急いで避難しろ！","ENG":"Evacuate before the C.O.s start crawling up here!","TWN":"在侵蝕體爬上來之前盡快撤離！"},"stage":{"bg":"FRONTBAY_WALL","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_MONITOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"……이상으로 현 상황에 대한 보고를 마칩니다.","JPN":"……以上で現状況についての報告を終わります。","ENG":"...That concludes my report on the current situation.","TWN":"……以上為現況報告。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"솔직히 말하면, 무척이나 당황스럽군.","JPN":"正直言って、かなり動揺している。","ENG":"To be honest, this is quite baffling.","TWN":"說實話我很震驚。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>검은 범람</color>이 다시 발생했다고?","JPN":"<color=#ffd34c>黒い氾濫</color>がまた発生しただと？","ENG":"The <color=#ffd34c>Black Flood</color> has returned?","TWN":"又發生<color=#ffd34c>黑色洪災</color>了？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"저도 관측 결과가 의심스러워 몇 번이고 다시 조사했지만…….","JPN":"私も観測の結果が疑わしく、何度も調べたのですが……","ENG":"I rechecked the readings several times myself because they seemed off, but...","TWN":"我懷疑觀測結果，反覆檢查了好幾次……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"상황을 받아들이지 못하겠다는 것이 아니야.","JPN":"状況が飲み込めないわけではないんだ。","ENG":"It's not that I can't accept the situation.","TWN":"我不是不能接受現實。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"검은 범람의 주기는 계속해서 짧아지고 있었으니까.","JPN":"黒い氾濫の周期はどんどん短くなってきていたからな。","ENG":"The Black Flood's cycle has been growing shorter and shorter.","TWN":"畢竟黑色洪災的週期越來越短。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"다만…….","JPN":"ただ……","ENG":"It's just that...","TWN":"只是……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그걸 고려해도 지나치게 빨라요.","JPN":"それを考慮しても早すぎます。","ENG":"Even accounting for that, this is far too soon.","TWN":"就算如此，這也太快了。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"놈은 얼마 전, 인빈서블의 자폭으로 본체에 큰 타격을 입었습니다.","JPN":"クラーケンは直前の氾濫の際、インビンシブルの自爆によって本体に大きなダメージを受けました。","ENG":"The creature took heavy damage from the Invincible's self-destruction not long ago.","TWN":"那傢伙不久前才被無敵號自爆重創本體。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그 상처를 회복하는 데 몇 년은 걸릴 거라 예상했는데…….","JPN":"その怪我が回復するのに数年はかかると予想していたのに……","ENG":"We estimated it would take years for it to recover from that...","TWN":"我原本以為至少得花好幾年才能恢復……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그라운드 원의 시니어 르네께서 긴급한 통신을 요청하셨습니다.","JPN":"グラウンド・ワンのシニア・ルネから、緊急通信の要請です。","ENG":"Senior Renée of Ground One is requesting an urgent transmission.","TWN":"G1的Senior芮妮緊急請求通話。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"연결할까요?","JPN":"繋げましょうか？","ENG":"Shall I connect her?","TWN":"要接通嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"시니어 르네가 직접 연락할 정도면 보통 사안이 아니겠지.","JPN":"シニア・ルネが直接連絡してくるくらいだ。きっとただ事ではない。","ENG":"If Senior Renée is contacting us directly, it must be serious.","TWN":"竟能讓Senior芮妮親自聯絡，事情絕對不簡單。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"연결해 줘.","JPN":"繋げてくれ。","ENG":"Put her through.","TWN":"接吧。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"근육남! 그쪽 상황은 좀 괜찮아?!","JPN":"筋肉男！　そっちは大丈夫か！？","ENG":"Muscle-head! Are you all holding up over there?!","TWN":"肌肉男！你們那邊沒事吧？！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"안부를 나눌 새도 없이 말하는 것을 보니 그쪽에도 무슨 일이 생긴 모양이군.","JPN":"挨拶を交わす間もなく本題から入るのをみると、そっちにも何かあったんだな。","ENG":"If you're skipping the pleasantries, something's happened on your end too.","TWN":"連問候都省了，看來你們那邊也出事了。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"검은 범람이 시작되었다는 보고를 받았어.","JPN":"こちらは、黒い氾濫が始まったという報告を受けたところだが。","ENG":"We received a report the Black Flood has begun.","TWN":"我收到黑色洪災啟動的報告。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"설마… 대균열에 관한 문제가 생긴 건가?","JPN":"まさか……大亀裂絡みの問題が発生したのか？","ENG":"Wait... Is something wrong with the Grand Dimension Crevice?","TWN":"難道……大峽谷發生什麼問題了？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……역시 히키코모리보다는 눈치가 빠르네.","JPN":"……やはり、引きこもりよりは勘が鋭いな。","ENG":"...As expected, you're quicker on the uptake than that shut-in.","TWN":"……你果然比宅男敏銳。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};